import{_ as t,o as s,c as a,a2 as i}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"End-to-end testing","description":"","frontmatter":{"docSection":"contributors","docType":"guide","audiences":["contributor"]},"headers":[],"relativePath":"testing-e2e.md","filePath":"testing-e2e.md"}'),n={name:"testing-e2e.md"};function d(r,e,o,l,h,p){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="end-to-end-testing" tabindex="-1">End-to-end testing <a class="header-anchor" href="#end-to-end-testing" aria-label="Permalink to &quot;End-to-end testing&quot;">​</a></h1><p>Sovereign uses <a href="https://playwright.dev" target="_blank" rel="noreferrer">Playwright</a> for browser-driven end-to-end tests. The suite covers the <strong>golden paths</strong> — the most critical user-facing flows — and runs against the full stack (both apps booted by Playwright&#39;s <code>webServer</code> config).</p><h2 id="running-locally" tabindex="-1">Running locally <a class="header-anchor" href="#running-locally" aria-label="Permalink to &quot;Running locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install Playwright browsers (once — Chromium only by default in this project).</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chromium</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run all e2e tests (starts both apps if they&#39;re not already running).</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Keep your dev servers running across runs (faster):</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;                           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># in another terminal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # reuses existing servers</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Headed mode (watch the browser):</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --headed</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Interactive UI mode (run/debug individual tests):</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ui</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Debug a single test:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --debug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth.spec.ts</span></span></code></pre></div><p>Playwright injects E2E-only local defaults for <code>AUTH_SECRET</code> and <code>SOVEREIGN_ADMIN_KEY</code> when it starts the auth and runtime web servers. To run the suite with explicit values, set <code>E2E_AUTH_SECRET</code> and <code>E2E_ADMIN_KEY</code>.</p><p><strong>Refreshing stale auth state:</strong> the global setup saves login storage state to <code>.auth/</code>. If you change seed users or rotate secrets, delete the cache and re-run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .auth/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e</span></span></code></pre></div><p><strong>Opening trace files:</strong> when a test fails locally, Playwright writes a trace to <code>test-results/</code>. Open it with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show-trace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-results/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">test-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/trace.zip</span></span></code></pre></div><hr><h2 id="ci" tabindex="-1">CI <a class="header-anchor" href="#ci" aria-label="Permalink to &quot;CI&quot;">​</a></h2><p>The <code>e2e.yml</code> workflow is present but intentionally disabled while hosted E2E is deferred. Its source-path filter, setup, and artifact upload steps are kept ready for a future CI gate, but the job currently has <code>if: false</code>.</p><p>Run <code>pnpm test:e2e</code> manually before pushing changes that touch browser-facing flows, auth, middleware, platform plugins, or the Playwright harness.</p><p><strong>Required GitHub secrets:</strong></p><table tabindex="0"><thead><tr><th>Secret</th><th>Purpose</th></tr></thead><tbody><tr><td><code>E2E_AUTH_SECRET</code></td><td>HMAC signing secret for session cache (any base64 string)</td></tr><tr><td><code>E2E_ADMIN_KEY</code></td><td>Sovereign admin key for admin API calls</td></tr></tbody></table><p>Generate them with <code>openssl rand -base64 32</code>.</p><p>On failure the HTML report is uploaded as a workflow artifact (<code>playwright-report</code>, 7-day retention) — download and open <code>index.html</code> to view traces.</p><hr><h2 id="what-is-covered" tabindex="-1">What is covered <a class="header-anchor" href="#what-is-covered" aria-label="Permalink to &quot;What is covered&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Spec</th><th>Tests</th><th>Description</th></tr></thead><tbody><tr><td><code>auth.spec.ts</code></td><td>4</td><td>Unauthenticated redirect, login, wrong password, logout</td></tr><tr><td><code>launcher.spec.ts</code></td><td>3</td><td>Plugin grid visible, tile click navigates, chrome plugins absent</td></tr><tr><td><code>account.spec.ts</code></td><td>3</td><td>Profile page renders, display name update, theme toggle</td></tr><tr><td><code>console.spec.ts</code></td><td>4</td><td>Admin access, user 403, plugin list, user list</td></tr><tr><td><code>navigation.spec.ts</code></td><td>3</td><td>Root rewrite, brand link, avatar menu keyboard</td></tr><tr><td><code>password-reset.spec.ts</code></td><td>7</td><td>Forgot-password, invalid tokens, reset email link, single-use token</td></tr><tr><td><code>paywall.spec.ts</code></td><td>3</td><td>Paywalled redirect, tier display, token import + access</td></tr><tr><td><strong>Total</strong></td><td><strong>27</strong></td><td></td></tr></tbody></table><hr><h2 id="what-is-not-yet-covered-deferred" tabindex="-1">What is NOT yet covered (deferred) <a class="header-anchor" href="#what-is-not-yet-covered-deferred" aria-label="Permalink to &quot;What is NOT yet covered (deferred)&quot;">​</a></h2><p>These flows were identified during planning but are not in the current golden-path suite. They are candidates for future expansion:</p><table tabindex="0"><thead><tr><th>Flow</th><th>Rationale for deferral</th></tr></thead><tbody><tr><td>TOTP / 2FA enrollment and challenge</td><td>Requires OTP code generation in tests; adds test-tooling complexity</td></tr><tr><td>Passkey (WebAuthn) registration &amp; login</td><td>Needs Playwright&#39;s experimental WebAuthn emulation (<code>page.context().addInitScript</code> + CTAP2 virtual authenticator)</td></tr><tr><td>Account — avatar upload</td><td>File upload + image serving; high value but needs <code>page.setInputFiles</code> + S3/local assertion</td></tr><tr><td>Account — password change</td><td>Low risk of regression; covered by unit tests on the auth route</td></tr><tr><td>Account — session list and revocation</td><td>Multi-context session management; complex setup</td></tr><tr><td>Account — data export / import</td><td>ZIP download/upload; complex assertion</td></tr><tr><td>Account — data consents</td><td>Requires two installed plugins with <code>sdk.data.provide</code>; setup-heavy</td></tr><tr><td>Account — notifications tab</td><td>Depends on SSE stream delivery timing</td></tr><tr><td>Account — push notifications</td><td>Requires VAPID keys and service worker; browser permission</td></tr><tr><td>Account — billing / entitlements management</td><td>Covered by paywall spec; fine-grained CRUD deferred</td></tr><tr><td>Console — plugin enable/disable toggle</td><td>State mutation that can break other tests; better as an isolated integration test</td></tr><tr><td>Console — invite user (sends email)</td><td>Requires Mailpit + mailbox assertion</td></tr><tr><td>Console — broadcast notification</td><td>Multi-user notification delivery; coordination overhead</td></tr><tr><td>Console — system health detail</td><td>Covered by <code>/api/admin/health</code> unit tests</td></tr><tr><td>Console — license key generation</td><td>Covered by the paywall spec&#39;s global-setup; fine-grained UI deferred</td></tr><tr><td>Activity log — event capture</td><td>Correctness verified by unit tests; pagination and filter UI deferred</td></tr><tr><td>Mobile viewport / responsive shell</td><td>Playwright can emulate; deferred as separate mobile-viewport spec</td></tr><tr><td>Offline banner</td><td>Requires Playwright <code>page.context().setOffline(true)</code> emulation</td></tr><tr><td>Plugin compatibility badge</td><td>Requires installing a plugin with a mismatched <code>minPlatformVersion</code></td></tr><tr><td>Root plugin switching</td><td>Admin-only settings change with page-reload verification; deferred</td></tr><tr><td>Cross-plugin data sharing</td><td>Requires two plugins with <code>sdk.data.provide/consume</code> registered</td></tr></tbody></table><p>Browser mobile emulation is not enough for installed-PWA behavior. For iPhone or Android PWA checks before deploy, use a production local build through an HTTPS tunnel and install from the device browser. See <a href="./pwa-real-device-testing.html"><code>docs/pwa-real-device-testing.md</code></a> for the human/agent workflow, local network vs HTTPS tunnel tradeoffs, device checklist, and iPhone cache reset steps.</p><hr><h2 id="adding-new-tests" tabindex="-1">Adding new tests <a class="header-anchor" href="#adding-new-tests" aria-label="Permalink to &quot;Adding new tests&quot;">​</a></h2><ol><li>Create <code>__tests__/e2e/&lt;area&gt;.spec.ts</code>.</li><li>Import from <code>./fixtures</code> for authenticated pages (<code>adminPage</code>, <code>userPage</code>), or from <code>@playwright/test</code> for unauthenticated tests.</li><li>Use ARIA selectors (<code>getByRole</code>, <code>getByLabel</code>, <code>aria-label=</code>) rather than CSS class names (Next.js scopes CSS Module names; they&#39;re stable in dev but shouldn&#39;t be relied on in tests).</li><li>Use <code>test.afterEach</code> / <code>page.request</code> for cleanup — do not leave mutated state that affects subsequent tests (especially for <code>workers: 1</code> serialised runs).</li><li>Run <code>pnpm test:e2e</code> locally before pushing.</li></ol><p>The global setup (<code>global-setup.ts</code>) runs once per Playwright process. If your test requires additional one-time setup (e.g. seeding a specific record), add it there and write the cleanup in the spec&#39;s <code>test.afterEach</code>.</p>`,29)])])}const u=t(n,[["render",d]]);export{g as __pageData,u as default};
